# CRITICAL: Use copy.deepcopy() to copy structure
import copy
new_config = {}
for route_id, config in current_bus_schedule.items():
    new_config[route_id] = {"timetable": []}
    for period in config['timetable']:
        new_period = {
            "time_range": period["time_range"],  # DO NOT MODIFY - copy exact time range
            "headway": 150,  # Modify headway as needed
            "schedule": copy.deepcopy(period["schedule"])  # COPY exact station list
        }
        # Modify dwell times
        for station in new_period["schedule"]:
            station["dwell_time"] = 18  # Modify as needed
        new_config[route_id]["timetable"].append(new_period)
