# Get bus states
data = read_bus_states()
if 'error' in data:
    print(f"Error: {data['error']}")
else:
    for snapshot in data['snapshots']:
        sim_time = snapshot['simulation_time']
        bus_data = snapshot['bus']
        for line_id, state in bus_data['lines'].items():
            print(f"{line_id} at {sim_time}s: {state['active_buses']} buses, headway={state['headway']}s")
            for station_id, station in state['stations'].items():
                if station.get('waiting_count', 0) > 0:
                    print(f"  Station {station_id}: {station['waiting_count']} waiting")
